            {cols.map((c) => <th key={c} style={{ padding: "10px 14px", textAlign: "left", fontWeight: 600, color: dark ? "rgba(255,255,255,.7)" : "#374151", fontSize: 12, whiteSpace: "nowrap" }}>{c}</th>)}
          </tr>
        </thead>
        <tbody>
          {rows.length === 0 ? (
            <tr><td colSpan={cols.length} style={{ textAlign: "center", padding: 32, color: "#9ca3af" }}>No records found</td></tr>
          ) : rows.map((row, i) => (
            <tr key={i} style={{ borderTop: dark ? "1px solid rgba(255,255,255,.06)" : "1px solid #f3f4f6", background: i % 2 === 0 ? "transparent" : (dark ? "rgba(255,255,255,.02)" : "#fafafa") }}>
              {row.map((cell, j) => <td key={j} style={{ padding: "10px 14px", color: dark ? "rgba(255,255,255,.85)" : "#1f2937", verticalAlign: "middle" }}>{cell}</td>)}
            </tr>
          ))}
        </tbody>
      </table>
    </div>
  );
}

// ─── SECTION HEADER ──────────────────────────────────────────────────────────
function SectionHeader({ title, subtitle, dark, actions }) {
  return (
    <div style={{ display: "flex", alignItems: "flex-start", justifyContent: "space-between", flexWrap: "wrap", gap: 12, marginBottom: 24 }}>
      <div>
        <h1 style={{ margin: 0, fontSize: 22, fontWeight: 700, color: dark ? "#f3f4f6" : "#111" }}>{title}</h1>
        {subtitle && <p style={{ margin: "4px 0 0", fontSize: 13, color: dark ? "rgba(255,255,255,.5)" : "#6b7280" }}>{subtitle}</p>}
      </div>
      {actions && <div style={{ display: "flex", gap: 10 }}>{actions}</div>}
    </div>
  );
}

function Btn({ label, onClick, primary, danger }) {
  const bg = primary ? "#d97706" : danger ? "#dc2626" : "transparent";
  const border = primary ? "#d97706" : danger ? "#dc2626" : "#d1d5db";
  const col = primary || danger ? "#fff" : "#374151";
  return (
    <button onClick={onClick} style={{ padding: "9px 18px", borderRadius: 8, border: "1px solid " + border, background: bg, color: col, cursor: "pointer", fontSize: 13, fontWeight: 500, transition: "opacity .15s" }}
      onMouseOver={e => e.currentTarget.style.opacity = ".85"} onMouseOut={e => e.currentTarget.style.opacity = "1"}>
      {label}
    </button>
  );
}

function Input({ label, value, onChange, type = "text", options, dark }) {
  const style = { width: "100%", padding: "9px 12px", border: "1px solid " + (dark ? "rgba(255,255,255,.15)" : "#d1d5db"), borderRadius: 8, fontSize: 13, background: dark ? "rgba(255,255,255,.05)" : "#fff", color: dark ? "#f3f4f6" : "#111", boxSizing: "border-box" };
  return (
    <div style={{ marginBottom: 14 }}>
      <label style={{ display: "block", fontSize: 12, fontWeight: 600, color: dark ? "rgba(255,255,255,.6)" : "#374151", marginBottom: 5 }}>{label}</label>
      {options ? (
        <select value={value} onChange={e => onChange(e.target.value)} style={style}>
          <option value="">— Select —</option>
          {options.map((o) => <option key={o.value} value={o.value}>{o.label}</option>)}
        </select>
      ) : (
        <input type={type} value={value} onChange={e => onChange(e.target.value)} style={style} />
      )}
    </div>
  );
}

// ─── MINI BAR CHART ──────────────────────────────────────────────────────────
function MiniBarChart({ data, dark }) {
  const max = Math.max(...data.map((d) => d.v));
  return (
    <div style={{ display: "flex", alignItems: "flex-end", gap: 6, height: 80, padding: "0 4px" }}>
      {data.map((d, i) => (
        <div key={i} style={{ flex: 1, display: "flex", flexDirection: "column", alignItems: "center", gap: 4 }}>
          <div style={{ width: "100%", background: "#d97706", borderRadius: "3px 3px 0 0", height: Math.max(4, (d.v / max) * 60), transition: "height .4s ease" }}></div>
          <span style={{ fontSize: 9, color: dark ? "rgba(255,255,255,.4)" : "#9ca3af", whiteSpace: "nowrap" }}>{d.l}</span>
        </div>
      ))}
    </div>
  );
}

