// ─── COLLECTIONS ─────────────────────────────────────────────────────────────
function Collections({ dark, toast, setPreview }) {
  const [memberId, setMemberId] = useState("");
  const [groupId, setGroupId] = useState("");
  const [amount, setAmount] = useState("");
  const [mode, setMode] = useState("");
