                <div style={{ fontWeight: 700, fontSize: 15, color: dark ? "#f3f4f6" : "#111" }}>{g?.name} – Installment #{a.installment}</div>
                <div style={{ fontSize: 12, color: dark ? "rgba(255,255,255,.5)" : "#6b7280", marginTop: 3 }}>Date: {a.date} · Base: {fmt(a.baseAmount)}</div>
                {winner && <div style={{ fontSize: 12, color: dark ? "rgba(255,255,255,.5)" : "#6b7280" }}>Winner: {winner.name} · Bid: {fmt(a.bidAmount)}</div>}
              </div>
              <div style={{ display: "flex", alignItems: "center", gap: 12 }}>
                <Badge text={a.status} color={a.status === "Completed" ? "green" : a.status === "Scheduled" ? "blue" : "gray"} />
                {a.status === "Completed" && <Btn label="View Certificate →" onClick={() => genCert(a)} />}
                {a.status === "Scheduled" && <Btn label="Conduct Auction" onClick={() => toast.add("Auction module opening…")} primary />}
              </div>
            </div>
          );
        })}
      </div>
    </div>
  );
}

// ─── PRIZE PAYMENTS ───────────────────────────────────────────────────────────
function Prizes({ dark, toast, setPreview }) {
  const [winnerId, setWinnerId] = useState("");
  const [auctionId, setAuctionId] = useState("");

  const genReceipt = () => {
    const a = AUCTIONS.find(x => x.id === auctionId);
    const m = memberById(winnerId);
    const g = a ? groupById(a.groupId) : null;
    const s = g ? schemeById(g.schemeId) : null;
    if (!m || !a) { toast.add("Select winner and auction", "error"); return; }
    setPreview({
      title: "Prize Payment Receipt",
      docNo: "PPR" + genId(""),
      member: m,
      chit: { "Group": g?.name, "Scheme": s?.name, "Auction Date": a.date, "Installment": "#" + a.installment },
      payments: { headers: ["Description", "Amount"], rows: [["Prize Amount (Bid)", fmt(a.bidAmount)], ["TDS @5%", "-" + fmt(a.bidAmount * 0.05)], ["Net Disbursement", fmt(Math.round(a.bidAmount * 0.95))]] },
      amount: Math.round(a.bidAmount * 0.95),
      notes: "Prize disbursed via NEFT. UTR will be shared separately."
    });
  };

  return (
    <div>
      <SectionHeader title="Prize Payments" subtitle="Disburse prize amounts to auction winners" dark={dark} />
      <div style={{ background: dark ? "rgba(255,255,255,.05)" : "#fff", border: dark ? "1px solid rgba(255,255,255,.1)" : "1px solid #e5e7eb", borderRadius: 12, padding: 24, marginBottom: 24 }}>
        <div style={{ display: "grid", gridTemplateColumns: "1fr 1fr", gap: "0 20px" }}>
          <Input label="Winner (Member)" value={winnerId} onChange={setWinnerId} dark={dark} options={MEMBERS.map(m => ({ value: m.id, label: m.name }))} />
          <Input label="Auction" value={auctionId} onChange={setAuctionId} dark={dark} options={AUCTIONS.filter(a => a.status === "Completed").map(a => ({ value: a.id, label: a.id + " – " + groupById(a.groupId)?.name }))} />
        </div>
        <Btn label="Generate Prize Receipt →" onClick={genReceipt} primary />
      </div>

      <Table dark={dark} cols={["Auction", "Group", "Winner", "Bid Amount", "Net Payout", "Date", "Status"]}
        rows={AUCTIONS.filter(a => a.status === "Completed").map(a => {
          const g = groupById(a.groupId); const w = memberById(a.winnerId);
          return [a.id, g?.name, w?.name, fmt(a.bidAmount), fmt(Math.round(a.bidAmount * 0.95)), a.date, <Badge key={a.id} text="Disbursed" color="green" />];
        })} />
    </div>
  );
}

// ─── ACCOUNTING ──────────────────────────────────────────────────────────────
function Accounting({ dark }) {
  const totalCollected = COLLECTIONS.filter(c => c.status === "Paid").reduce((s, c) => s + c.amount, 0);
  const totalPrize = AUCTIONS.filter(a => a.bidAmount).reduce((s, a) => s + a.bidAmount, 0);
  const commission = totalCollected * 0.05;
  return (
    <div>
      <SectionHeader title="Accounting" subtitle="Financial overview and ledger summary" dark={dark} />
      <div style={{ display: "grid", gridTemplateColumns: "repeat(auto-fit,minmax(180px,1fr))", gap: 16, marginBottom: 24 }}>
        <StatCard label="Total Collected" value={fmt(totalCollected)} color="#16a34a" dark={dark} />
        <StatCard label="Prize Payouts" value={fmt(totalPrize)} color="#d97706" dark={dark} />
        <StatCard label="Commission Earned" value={fmt(Math.round(commission))} color="#2563eb" dark={dark} />
        <StatCard label="Net Profit" value={fmt(Math.round(commission - 45000))} color="#7c3aed" dark={dark} />
      </div>
      <div style={{ background: dark ? "rgba(255,255,255,.05)" : "#fff", border: dark ? "1px solid rgba(255,255,255,.1)" : "1px solid #e5e7eb", borderRadius: 12, padding: 20 }}>
        <div style={{ fontSize: 14, fontWeight: 600, color: dark ? "#f3f4f6" : "#111", marginBottom: 14 }}>Transaction Ledger</div>
        <Table dark={dark} cols={["Date", "Type", "Reference", "Debit", "Credit", "Balance"]}
          rows={[
            ["2024-06-01", "Collection", "RCP2024001", "–", fmt(5000), fmt(320000)],
            ["2024-06-02", "Collection", "RCP2024002", "–", fmt(5000), fmt(325000)],
            ["2024-06-10", "Prize Payout", "PPR001", fmt(85000), "–", fmt(240000)],
            ["2024-06-15", "Commission", "COM001", "–", fmt(4250), fmt(244250)],
            ["2024-06-20", "Salary", "SAL001", fmt(45000), "–", fmt(199250)],
          ]} />
      </div>
    </div>
  );
}

// ─── REPORTS ─────────────────────────────────────────────────────────────────
