  const genReport = (type) => {
    setPreview({
      title: type + " Report",
      docNo: "RPT" + genId(""),
      member: null,
      chit: { "Period": "June 2024", "Generated By": "Admin", "Branch": "Chennai HQ" },
      payments: {
        headers: ["Group", "Members", "Collected", "Pending", "Auctions"],
        rows: GROUPS.map(g => {
          const cols = COLLECTIONS.filter(c => c.groupId === g.id);
          return [g.name, g.members.length, fmt(cols.filter(c => c.status === "Paid").reduce((s, c) => s + c.amount, 0)), fmt(cols.filter(c => c.status === "Pending").reduce((s, c) => s + c.amount, 0)), AUCTIONS.filter(a => a.groupId === g.id).length];
        })
      },
      amount: COLLECTIONS.filter(c => c.status === "Paid").reduce((s, c) => s + c.amount, 0),
