  const reports = [
    { name: "Monthly Collection Report", desc: "Group-wise collection summary", icon: "💳" },
    { name: "Member Activity Report", desc: "Payment history for all members", icon: "👥" },
    { name: "Auction Summary Report", desc: "All auctions with winners and bids", icon: "🔨" },
    { name: "Profit & Loss Statement", desc: "Income, expenses and net profit", icon: "📊" },
